COPY public.concept (exam_key, svc, ord, content) FROM stdin;
aws/sap-c02	리전 / 가용 영역(AZ)	0	{"ko": {"vs": "**리전**(지리적 격리·데이터 기본 비복제) ↔ **가용 영역(AZ)**(리전 내 물리 격리+저지연 연결) ↔ **엣지 로케이션**(**CloudFront**/**Global Accelerator** 캐시·접점) ↔ **Local Zones**(대도시 근접 초저지연).", "cat": "네트워킹", "key": "리전마다 보통 **가용 영역(AZ, Availability Zone)** 3개 이상. AZ는 전원·냉각·네트워크가 독립이고 수 km 떨어져 있으나 1~2ms 저지연 전용망으로 연결된다. **서브넷**은 정확히 한 AZ에 속하므로 '다중 AZ'는 곧 '여러 AZ의 서브넷에 분산'을 뜻한다.", "rel": [42, 45, 52, 56, 72, 79, 81, 90, 94, 96, 97, 106, 110, 121, 144, 149, 154, 157, 161, 163, 169, 174, 177, 185, 186, 190, 192, 202, 240, 253, 263, 270, 273, 300, 305, 312, 318, 331, 340, 351], "abbr": "Region/AZ", "cost": "인프라 구분 자체는 무료. 다만 **동일 리전 AZ 간** 데이터 전송이 약 $0.01/GB(양방향) 과금되고 **리전 간** 전송은 더 높다 → 트래픽 많은 통신은 같은 AZ 배치로 비용을 줄인다.", "deff": "AWS 글로벌 인프라의 기본 단위. **리전(Region)**은 지리적으로 분리된 독립 영역이고, **가용 영역(AZ, Availability Zone)**은 한 리전 안에서 물리적으로 격리된 1개 이상의 데이터센터 묶음이다.", "reln": 83, "trap": "**AZ 이름**(us-east-1a)은 계정마다 다른 물리 AZ에 매핑되므로 계정 간 비교에는 **AZ ID**(use1-az1)를 써야 한다. 글로벌 서비스(**AWS IAM**·**Amazon Route 53**·**Amazon CloudFront**)는 리전·AZ와 무관하다. 단일 AZ 자원(인스턴스 스토어, Single-AZ **RDS**, **Local Zones**)은 그 AZ 장애 시 손실된다.", "when": "**다중 AZ(Multi-AZ)** 배포로 단일 AZ 장애를 견디는 고가용성 구성(여러 AZ의 **EC2 Auto Scaling**+ALB, **RDS** Multi-AZ, **Amazon EFS**). 리전 선택은 지연·데이터 주권(규정)·서비스 가용성·비용을 기준으로 한다.", "detail": "AWS는 **리전 > 가용 영역(AZ) > 데이터센터** 계층으로 인프라를 구성한다. 한 리전의 AZ들은 독립 전원·냉각·물리 보안을 갖되 완전 이중화된 저지연 광케이블로 묶여 있어 동기 복제(예 **RDS** Multi-AZ, **Amazon Aurora**)가 가능하다. **Amazon VPC**는 리전 범위이고 그 안의 **서브넷**은 단일 AZ에 고정되므로, 고가용성 설계의 핵심은 '워크로드를 최소 2~3개 AZ에 분산'하는 것이다. ALB·NLB는 활성화된 AZ로 트래픽을 분산하고 **EC2 Auto Scaling**은 AZ 균형을 자동으로 유지한다. 리전 전체 장애나 재해 복구(DR) 요구에는 다중 리전(액티브-액티브/액티브-패시브, **Amazon Route 53** 라우팅+데이터 복제)으로 확장한다. SAP-C02에서는 'AZ 격리 수준', 'AZ ID와 이름의 차이', 'AZ 간 전송 비용', '단일 AZ 서비스 식별', '다중 AZ vs 다중 리전 트레이드오프'가 자주 출제된다."}}
aws/sap-c02	Amazon VPC	1	{"ko": {"vs": "서브넷(공용/사설), **Transit Gateway**(다중 **VPC** 연결)", "cat": "네트워킹", "key": "리전 범위, AZ에 서브넷 배치. CIDR(보조 CIDR 추가 가능). 기본 라우팅 테이블/**NACL**/보안그룹 제공.", "rel": [6, 10, 16, 21, 22, 25, 34, 35, 45, 47, 50, 53, 54, 55, 61, 62, 65, 67, 70, 73, 76, 77, 79, 80, 82, 90, 97, 100, 111, 112, 122, 127, 135, 136, 137, 138, 143, 149, 150, 151], "abbr": "VPC", "cost": "VPC 자체 무료. NAT GW·엔드포인트·전송 등 부가 리소스가 비용.", "deff": "계정 전용 가상 네트워크. 서브넷·라우팅·게이트웨이로 격리된 IP 공간 구성.", "reln": 140, "trap": "**VPC**는 리전 단위, 서브넷은 AZ 단위. CIDR 겹치면 피어링/**TGW** 라우팅 불가.", "when": "모든 워크로드의 네트워크 기반. 격리·세분화가 필요할 때.", "detail": "**VPC**는 리전 내에서 정의한 CIDR 블록을 기반으로 소프트웨어 정의 네트워크를 구성하며, 라우팅 테이블·**NACL**·SG·게이트웨이가 함께 동작해 패킷 흐름과 격리를 결정한다. 운영상 핵심은 IP 설계로, 기본 /16과 보조 CIDR을 미리 계획해야 향후 피어링·**TGW** 확장 시 중복 충돌을 피한다. 대표 패턴은 멀티 AZ에 공용/사설/DB 서브넷을 계층화하고 Flow Logs로 트래픽을 감사하는 구조다. SAP-C02에서는 IP 고갈, CIDR 중복으로 인한 연결 불가, IPAM을 통한 대규모 주소 관리, **DNS** 옵션(enableDnsHostnames/Support) 선택이 자주 출제된다."}}
aws/sap-c02	서브넷 / 라우팅 테이블	2	{"ko": {"vs": "**NACL**(서브넷 단위 스테이트리스), 보안그룹(인스턴스 단위 스테이트풀)", "cat": "네트워킹", "key": "공용 서브넷=**IGW** 경로 보유, 사설=**NAT** 경유. 한 서브넷=한 AZ.", "rel": [16, 25, 34, 35, 47, 65, 70, 73, 76, 79, 82, 90, 97, 109, 112, 122, 136, 149, 152, 153, 157, 176, 180, 189, 192, 205, 227, 240, 253, 275, 290, 293, 320, 326, 335, 351, 354, 358, 360, 366], "abbr": "Subnet", "cost": "무료(트래픽/부가 리소스만 과금).", "deff": "VPC를 AZ별로 나눈 IP 구획. 라우팅 테이블이 트래픽 경로 결정.", "reln": 73, "trap": "서브넷은 AZ를 넘지 못함. 0.0.0.0/0 경로 대상이 공용/사설을 가름.", "when": "계층 분리(웹/앱/DB), AZ 다중화.", "detail": "서브넷은 **VPC** CIDR을 쪼갠 AZ 단위 구획이고, 각 서브넷에 연결된 라우팅 테이블의 0.0.0.0/0 대상이 공용(**IGW**)인지 사설(**NAT**)인지를 결정한다. 한 서브넷에는 라우팅 테이블 하나만 연결되지만 하나의 테이블은 여러 서브넷이 공유할 수 있어 계층별 경로 관리가 쉽다. 가용성 확보를 위해 동일 계층 서브넷을 여러 AZ에 분산하고 **ALB**·NAT를 AZ별로 배치하는 패턴이 표준이다. SAP-C02에서는 서브넷이 AZ 경계를 넘지 못한다는 점, 가용 IP는 AWS가 예약한 5개를 뺀 수라는 점, 라우팅 우선순위(롱기스트 프리픽스 매치)가 자주 시험된다."}}
aws/sap-c02	인터넷 게이트웨이	3	{"ko": {"vs": "**NAT** Gateway(아웃바운드 전용)", "cat": "네트워킹", "key": "공용 서브넷 라우팅(0.0.0.0/0→**IGW**) + 퍼블릭 IP/**EIP** 필요.", "rel": [47, 55, 73, 97, 182, 189, 205, 360, 410, 418, 445, 483, 484, 540, 604, 617], "abbr": "IGW", "cost": "IGW 무료. 데이터 전송(아웃바운드)만 과금.", "deff": "VPC와 인터넷 간 양방향 연결을 제공하는 수평 확장 게이트웨이.", "reln": 16, "trap": "**IGW**만으론 안 됨—퍼블릭 IP가 있어야 인터넷 접근. IPv6는 egress-only IGW.", "when": "인스턴스에 인바운드 인터넷 필요할 때.", "detail": "**IGW**는 **VPC**에 수평 확장·고가용성으로 부착되는 단일 객체로, 아웃바운드 시 사설 IP를 퍼블릭 IP로 **NAT** 변환하고 인바운드 시 역변환해 인터넷과 양방향 통신을 가능케 한다. 인터넷 접근 성립 조건은 ①IGW 부착 ②라우팅 0.0.0.0/0→IGW ③인스턴스의 퍼블릭/**EIP** ④SG·**NACL** 허용 네 가지가 모두 충족돼야 한다. 공용 서브넷의 진정한 정의는 라우팅 테이블이 IGW를 가리키는지 여부다. SAP-C02에서는 IPv6 아웃바운드 전용 통신에 egress-only IGW를 쓰는 선택, 퍼블릭 IP 없는 인스턴스가 인터넷에 나가지 못하는 시나리오가 단골이다."}}
aws/sap-c02	NAT 게이트웨이	4	{"ko": {"vs": "**NAT** 인스턴스(자가관리·저렴·관리부담), egress-only **IGW**(IPv6)", "cat": "네트워킹", "key": "AZ별 배치(고가용성은 AZ마다), **EIP** 연결, 자동 확장. 시간+데이터 과금.", "rel": [21, 35, 47, 73, 79, 97, 127, 136, 149, 152, 157, 183, 197, 205, 267, 328, 335, 351, 360, 372, 410, 418, 445, 453, 455, 483, 484, 547, 604, 609, 617, 637], "abbr": "NAT GW", "cost": "시간당 + 처리 데이터(GB) 과금 — 비용 큼. 엔드포인트로 우회 절감.", "deff": "사설 서브넷 인스턴스의 아웃바운드 인터넷(인바운드 차단)을 관리형으로 제공.", "reln": 32, "trap": "AZ 장애 대비 AZ마다 **NAT** GW 필요. 비용 큼→**VPC** 엔드포인트로 **S3**/DDB 트래픽 우회.", "when": "사설 인스턴스가 패치/외부 API 호출 시.", "detail": "**NAT** GW는 특정 서브넷에 배치되어 사설 인스턴스의 아웃바운드 트래픽을 자신의 **EIP**로 변환해 인터넷으로 내보내며, 인바운드 개시 연결은 차단한다. 단일 AZ에 묶인 자원이라 그 AZ가 죽으면 다른 AZ 워크로드의 외부 통신이 끊기므로, 진정한 고가용성은 AZ마다 NAT GW를 두고 각 AZ 사설 라우팅을 자기 AZ NAT로 향하게 해야 한다. 대역폭은 5Gbps에서 최대 100Gbps까지 자동 확장된다. SAP-C02에서는 NAT 데이터 처리 비용 절감을 위해 **S3**·**DynamoDB** 트래픽을 Gateway 엔드포인트로 우회시키는 선택과, AZ 간 NAT 경유로 발생하는 교차 AZ 전송 비용이 자주 출제된다."}}
aws/sap-c02	보안 그룹 / 네트워크 ACL	5	{"ko": {"vs": "SG vs **NACL**: 상태유지/평가단위 차이", "cat": "네트워킹", "key": "SG는 허용 규칙만(반환트래픽 자동허용). **NACL**은 허용+거부, 순번 평가.", "rel": [35, 36, 47, 50, 51, 73, 76, 112, 127, 151, 152, 153, 156, 158, 180, 205, 216, 275, 320, 335, 358, 403, 420, 421, 453, 488, 530, 547, 548, 558, 592, 604, 617, 630, 642, 644], "abbr": "SG/NACL", "cost": "무료.", "deff": "SG=인스턴스(ENI) 단위 스테이트풀 방화벽, NACL=서브넷 단위 스테이트리스.", "reln": 36, "trap": "**NACL**은 스테이트리스라 인/아웃 둘 다 열어야 함(임시포트). SG는 거부 규칙 불가.", "when": "SG=기본 보안, **NACL**=서브넷 광역 차단(특정 IP 블록).", "detail": "SG는 **ENI**에 적용되는 스테이트풀 방화벽으로 허용 규칙만 두면 반환 트래픽이 자동 허용되며, 다른 SG를 소스로 참조해 동적 멤버십 기반 규칙을 만들 수 있다. **NACL**은 서브넷 경계의 스테이트리스 필터로 규칙 번호 오름차순 평가에 허용·거부를 모두 지원하지만, 반환 트래픽을 자동 추적하지 않아 임시 포트(1024-65535)를 인바운드/아웃바운드 양방향으로 열어야 한다. 두 계층은 서로 다른 경계에 위치해 인바운드는 NACL(서브넷)→SG(ENI), 아웃바운드는 SG→NACL 순으로 패킷 경로상 적용되며, 어느 한쪽이 거부하면 통신은 차단된다. SAP-C02에서는 거부 규칙은 NACL로만 가능하다는 점(SG는 허용만 지원), 특정 IP 대역 광역 차단은 NACL, 인스턴스 단위 세밀 제어는 SG라는 역할 구분, SG 참조 체이닝이 핵심 출제 포인트다."}}
aws/sap-c02	VPC 피어링	6	{"ko": {"vs": "**Transit Gateway**(허브앤스포크·전이 라우팅)", "cat": "네트워킹", "key": "리전/계정 간 가능. CIDR 겹치면 불가. 양쪽 라우팅+SG 설정.", "rel": [10, 16, 53, 61, 70, 77, 80, 82, 112, 136, 138, 157, 180, 189, 227, 263, 267, 296, 335, 354, 409, 436, 468, 503, 540, 543, 548, 609, 632, 637], "abbr": "Peering", "cost": "피어링 무료. AZ 간/리전 간 데이터 전송 과금.", "deff": "두 VPC를 1:1 사설 연결. 전이적 라우팅 불가.", "reln": 30, "trap": "전이 라우팅 안 됨(A-B, B-C여도 A-C 불가)→다수면 **TGW**. 대역폭 제한 없음.", "when": "소수 **VPC** 간 직접 연결.", "detail": "피어링은 두 **VPC**의 **ENI** 간 트래픽을 AWS 백본으로 직접 라우팅하는 1:1 연결로, 별도 게이트웨이나 대역폭 병목이 없고 동일/교차 리전·교차 계정을 지원한다. 핵심 제약은 비전이성으로, A-B와 B-C가 연결돼도 A는 B를 경유해 C에 도달할 수 없어 풀메시 구성 시 연결 수가 N(N-1)/2로 폭증한다. 따라서 소수 VPC 직결에 적합하고 다수면 **TGW**가 정석이다. SAP-C02에서는 CIDR 중복 시 연결 불가, 양쪽 라우팅 테이블·SG 모두 갱신 필요, 피어를 경유한 **IGW**·**NAT**·엔드포인트 공유가 안 된다는 엣지 라우팅 제한이 자주 시험된다."}}
aws/sap-c02	Transit Gateway	7	{"ko": {"vs": "**VPC** 피어링(소규모), **Cloud WAN**(글로벌 관리형)", "cat": "네트워킹", "key": "어태치먼트(**VPC**/VPN/**DX**/Peering), 라우팅 테이블로 분리. 인터리전 피어링.", "rel": [10, 16, 34, 50, 54, 61, 70, 77, 80, 82, 135, 136, 153, 157, 189, 192, 227, 230, 267, 293, 296, 320, 326, 335, 358, 377, 378, 439, 468, 470, 472, 484, 487, 488, 503, 540, 543, 548, 637], "abbr": "TGW", "cost": "어태치먼트 시간당 + 처리 데이터(GB) 과금.", "deff": "수천 개 VPC/온프레미스를 허브앤스포크로 연결하는 리전 라우터.", "reln": 39, "trap": "리전 단위(인터리전은 **TGW** 피어링). **RAM**으로 계정 간 공유.", "when": "대규모 다중 **VPC**·하이브리드 네트워크 중앙화.", "detail": "**TGW**는 **VPC**·VPN·**Direct Connect**·다른 TGW를 어태치먼트로 연결해 중앙 라우팅하는 리전 단위 라우터로, 여러 TGW 라우팅 테이블을 두고 어태치먼트 연결을 분리하면 도메인 격리(예: 프로덕션-비프로덕션 비통신)를 구현한다. 피어링과 달리 전이 라우팅을 지원해 허브앤스포크로 수천 VPC를 단순화한다. 대표 패턴은 중앙 인스펙션 VPC로 트래픽을 끌어 방화벽 검사 후 분배하거나 공유 서비스 VPC를 모든 스포크에 노출하는 구조다. SAP-C02에서는 TGW가 리전 한정이라 인터리전은 TGW 피어링이 필요하다는 점, **RAM**으로 계정 간 공유, 어태치먼트당 시간·데이터 비용이 자주 출제된다."}}
